import { supabase, isSupabaseConfigured, supabaseUrl } from "../lib/supabaseClient.js";

/** @type {import("@supabase/supabase-js").Session | null} */
let currentSession = null;
/** @type {Array<(session: import("@supabase/supabase-js").Session | null) => void>} */
const sessionListeners = [];

function notifySessionChange() {
  sessionListeners.forEach((listener) => {
    try {
      listener(currentSession);
    } catch (e) {
      console.warn("session listener error:", e);
    }
  });
}

export function isSupabaseLoggedIn() {
  return Boolean(currentSession && currentSession.user);
}

export function onSupabaseSessionChange(listener) {
  if (typeof listener !== "function") return () => {};
  sessionListeners.push(listener);
  return () => {
    const idx = sessionListeners.indexOf(listener);
    if (idx >= 0) sessionListeners.splice(idx, 1);
  };
}

function getEl(id) {
  return document.getElementById(id);
}

function setText(id, text) {
  const el = getEl(id);
  if (el) el.textContent = text || "";
}

function buildInitials(name, email) {
  const nameText = String(name || "").trim();
  if (nameText) {
    const parts = nameText.split(/\s+/).filter(Boolean);
    if (parts.length >= 2) {
      return `${parts[0][0] || ""}${parts[1][0] || ""}`.toUpperCase();
    }
    return (parts[0] || "").slice(0, 2).toUpperCase();
  }
  const emailText = String(email || "").trim();
  if (emailText.includes("@")) {
    const local = emailText.split("@")[0].replace(/[^a-zA-Z0-9]/g, "");
    return (local.slice(0, 2) || "U").toUpperCase();
  }
  return "U";
}

function setAuthMessage(text, kind) {
  const msg = getEl("auth-message");
  if (!msg) return;
  msg.textContent = text || "";
  msg.classList.remove("text-emerald-600", "text-rose-600", "font-semibold", "text-slate-500");
  msg.classList.add("text-slate-500");
  if (kind === "ok") {
    msg.classList.remove("text-slate-500");
    msg.classList.add("text-emerald-600", "font-semibold");
  } else if (kind === "err") {
    msg.classList.remove("text-slate-500");
    msg.classList.add("text-rose-600", "font-semibold");
  }
}

function showAuthMode(mode) {
  const loginForm = getEl("auth-form-login");
  const regForm = getEl("auth-form-register");
  if (loginForm) loginForm.classList.toggle("hidden", mode !== "login");
  if (regForm) regForm.classList.toggle("hidden", mode !== "register");
}

function getSessionIdFromJwt(accessToken) {
  try {
    const parts = String(accessToken || "").split(".");
    if (parts.length < 2) return null;
    const payload = JSON.parse(atob(parts[1]));
    return payload && payload.session_id ? String(payload.session_id) : null;
  } catch {
    return null;
  }
}

async function enforceSingleSession(session) {
  if (!session || !session.access_token || !supabaseUrl) return;
  const currentSessionId = getSessionIdFromJwt(session.access_token);
  if (!currentSessionId) return;

  const endpoint = `${supabaseUrl}/functions/v1/enforce-single-session`;
  const res = await fetch(endpoint, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${session.access_token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ current_session_id: currentSessionId }),
  });
  if (!res.ok) {
    const raw = await res.text().catch(() => "");
    throw new Error(raw || `enforce-single-session HTTP ${res.status}`);
  }
}

async function loadProfileRow(userId) {
  if (!supabase || !userId) return null;
  const { data, error } = await supabase
    .from("profiles")
    .select("full_name,email")
    .eq("id", userId)
    .maybeSingle();
  if (error) {
    console.warn("profiles уншихад алдаа:", error.message);
    return null;
  }
  return data;
}

async function renderLoggedIn(session) {
  const loggedOut = getEl("auth-logged-out");
  const loggedIn = getEl("auth-logged-in");
  const notCfg = getEl("auth-not-configured");
  if (notCfg) notCfg.classList.add("hidden");
  if (loggedOut) loggedOut.classList.add("hidden");
  if (loggedIn) loggedIn.classList.remove("hidden");

  const user = session && session.user;
  const email = user && user.email ? user.email : "—";
  setText("auth-display-email", email === "—" ? "Имэйл: —" : `${email}`);

  setText("auth-display-name", "Уншиж байна…");
  const row = user ? await loadProfileRow(user.id) : null;
  const name =
    row && typeof row.full_name === "string" && row.full_name.trim()
      ? row.full_name.trim()
      : user && user.user_metadata && user.user_metadata.full_name
        ? String(user.user_metadata.full_name)
        : "—";
  setText("auth-display-name", name === "—" ? "Нэр: —" : `${name}`);
  setText("auth-avatar", buildInitials(name === "—" ? "" : name, email === "—" ? "" : email));
}

function renderLoggedOut() {
  const loggedOut = getEl("auth-logged-out");
  const loggedIn = getEl("auth-logged-in");
  const notCfg = getEl("auth-not-configured");
  if (notCfg) notCfg.classList.add("hidden");
  if (loggedIn) loggedIn.classList.add("hidden");
  if (loggedOut) loggedOut.classList.remove("hidden");
  showAuthMode("login");
  setAuthMessage("", null);
}

function renderNotConfigured() {
  const loggedOut = getEl("auth-logged-out");
  const loggedIn = getEl("auth-logged-in");
  const notCfg = getEl("auth-not-configured");
  if (loggedOut) loggedOut.classList.add("hidden");
  if (loggedIn) loggedIn.classList.add("hidden");
  if (notCfg) notCfg.classList.remove("hidden");
}

/**
 * @param {import("@supabase/supabase-js").Session | null} session
 */
export async function refreshAuthUi(session) {
  currentSession = session || null;
  notifySessionChange();
  if (!isSupabaseConfigured() || !supabase) {
    renderNotConfigured();
    return;
  }
  if (session && session.user) {
    await renderLoggedIn(session);
  } else {
    renderLoggedOut();
  }
}

function wireForms() {
  const switchToReg = getEl("auth-switch-to-register");
  const switchToLogin = getEl("auth-switch-to-login");
  if (switchToReg) {
    switchToReg.addEventListener("click", () => {
      showAuthMode("register");
      setAuthMessage("", null);
    });
  }
  if (switchToLogin) {
    switchToLogin.addEventListener("click", () => {
      showAuthMode("login");
      setAuthMessage("", null);
    });
  }

  const loginBtn = getEl("auth-login-btn");
  if (loginBtn) {
    loginBtn.addEventListener("click", async () => {
      if (!supabase) return;
      const email = (getEl("auth-email") && getEl("auth-email").value) || "";
      const password = (getEl("auth-password") && getEl("auth-password").value) || "";
      if (!email.trim() || !password) {
        setAuthMessage("И-мэйл, нууц үг оруулна уу.", "err");
        return;
      }
      setAuthMessage("Нэвтэрч байна…", null);
      loginBtn.disabled = true;
      const { data, error } = await supabase.auth.signInWithPassword({
        email: email.trim(),
        password,
      });
      loginBtn.disabled = false;
      if (error) {
        setAuthMessage(error.message || "Нэвтрэхэд алдаа гарлаа.", "err");
        return;
      }
      if (data.session) {
        try {
          await enforceSingleSession(data.session);
        } catch (e) {
          console.warn("single-session enforcement error:", e);
        }
      }
      setAuthMessage("Амжилттай нэвтэрлээ.", "ok");
      if (data.session) await refreshAuthUi(data.session);
    });
  }

  const regBtn = getEl("auth-register-btn");
  if (regBtn) {
    regBtn.addEventListener("click", async () => {
      if (!supabase) return;
      const fullName = (getEl("auth-full-name") && getEl("auth-full-name").value) || "";
      const email = (getEl("auth-reg-email") && getEl("auth-reg-email").value) || "";
      const password = (getEl("auth-reg-password") && getEl("auth-reg-password").value) || "";
      const confirmPassword =
        (getEl("auth-reg-password-confirm") && getEl("auth-reg-password-confirm").value) || "";
      if (!email.trim() || !password || password.length < 6) {
        setAuthMessage("И-мэйл, хамгийн багадаа 6 тэмдэгттэй нууц үг оруулна уу.", "err");
        return;
      }
      if (password !== confirmPassword) {
        setAuthMessage("Нууц үг таарахгүй байна.", "err");
        return;
      }
      setAuthMessage("Бүртгэж байна…", null);
      regBtn.disabled = true;
      const { data, error } = await supabase.auth.signUp({
        email: email.trim(),
        password,
        options: {
          data: {
            full_name: fullName.trim(),
          },
        },
      });
      regBtn.disabled = false;
      if (error) {
        setAuthMessage(error.message || "Бүртгэлд алдаа гарлаа.", "err");
        return;
      }
      if (data.session) {
        setAuthMessage("Бүртгэл амжилттай. Нэвтэрлээ.", "ok");
        await refreshAuthUi(data.session);
      } else {
        setAuthMessage("Бүртгэл үүслээ. И-мэйлээ баталгаажуулсны дараа нэвтэрнэ үү.", "ok");
      }
    });
  }

  const signOutBtn = getEl("auth-signout-btn");
  if (signOutBtn) {
    signOutBtn.addEventListener("click", async () => {
      if (!supabase) return;
      signOutBtn.disabled = true;
      const { error } = await supabase.auth.signOut();
      signOutBtn.disabled = false;
      if (error) {
        setAuthMessage(error.message || "Гарахад алдаа.", "err");
        return;
      }
      renderLoggedOut();
    });
  }
}

export function initSupabaseAuth() {
  if (!isSupabaseConfigured() || !supabase) {
    renderNotConfigured();
    return;
  }

  wireForms();

  supabase.auth.onAuthStateChange((_event, session) => {
    // Async Supabase дуудлага deadlock-оос зайлсхийхийн тулд defer хийнэ.
    setTimeout(() => {
      refreshAuthUi(session).catch((e) => console.warn("refreshAuthUi:", e));
    }, 0);
  });

  supabase.auth
    .getSession()
    .then(({ data: { session } }) => refreshAuthUi(session))
    .catch((e) => console.warn("getSession:", e));
}
